class MockCheckpointSaver:
    def __init__(self):
        self.db = {}
    def save(self, thread_id, state):
        self.db[thread_id] = state.copy()
    def load(self, thread_id):
        return self.db.get(thread_id, {})

def run_practice():
    saver = MockCheckpointSaver()
    saver.save('thread_1', {'step': 5})
    assert saver.load('thread_1') == {'step': 5}
    print('[PASS] Checkpoint persistence checks validated.')

if __name__ == '__main__':
    run_practice()
